-- {"operators": "INNER_JOIN,AGGREGATE,FILTER,HAVING", "complexity": "high", "is_incremental": true, "has_nulls": false, "has_cast": false, "has_case": false, "tables": "WAREHOUSE,DISTRICT,CUSTOMER,HISTORY"}
SELECT w.W_ID, d.D_ID, COUNT(*) AS customer_count, SUM(c.C_BALANCE) AS total_balance, MIN(c.C_BALANCE) AS min_balance, MAX(c.C_BALANCE) AS max_balance, SUM(h.H_AMOUNT) AS total_payments FROM WAREHOUSE w JOIN DISTRICT d ON w.W_ID = d.D_W_ID JOIN CUSTOMER c ON d.D_W_ID = c.C_W_ID AND d.D_ID = c.C_D_ID JOIN HISTORY h ON c.C_W_ID = h.H_C_W_ID AND c.C_D_ID = h.H_C_D_ID AND c.C_ID = h.H_C_ID GROUP BY w.W_ID, d.D_ID HAVING SUM(c.C_BALANCE) > 0 AND COUNT(*) > 1;
